@app.post("/tokens", response_model=TokenCreateResponse, tags=["Token Management"])
async def store_token(request: TokenCreateRequest):
    """
    Store a token in Redis cache.
    In production, this would be called by your OAuth 2.0 authorization server
    after issuing a token.
    """
    redis_conn = await RedisPool.get_connection()
    token_key = f"{TOKEN_PREFIX}{request.token}"

    now = datetime.now(timezone.utc)
    expires_at = now + timedelta(seconds=request.ttl_seconds)

    token_data = {
        "user_id": request.user_id,
        "email": request.email,
        "scopes": ",".join(request.scopes),
        "issued_at": now.isoformat(),
        "expires_at": expires_at.isoformat(),
    }

    try:
        pipeline = redis_conn.pipeline()
        pipeline.hset(token_key, mapping=token_data)
        pipeline.expire(token_key, request.ttl_seconds)
        await pipeline.execute()
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Failed to store token: {str(e)}",
        )

    return TokenCreateResponse(
        message="Token stored successfully",
        token=request.token,
        expires_in=request.ttl_seconds,
    )


@app.delete("/tokens/{token}", tags=["Token Management"])
async def revoke_token(token: str):
    """Revoke a token by removing it from Redis cache."""
    redis_conn = await RedisPool.get_connection()
    token_key = f"{TOKEN_PREFIX}{token}"

    try:
        deleted = await redis_conn.delete(token_key)
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Failed to revoke token: {str(e)}",
        )

    if not deleted:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail="Token not found",
        )

    return {"message": "Token revoked successfully"}


